     1→//! High-performance design matrix construction for statistical models
     2→//!
     3→//! This crate provides column-oriented design matrix builders that fuse
     4→//! transformations to eliminate intermediate allocations and leverage
     5→//! parallel computation for construction.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use formula::ModelSpec;
    11→use ndarray::Array2;
    12→
    13→/// Design matrix construction errors
    14→#[derive(thiserror::Error, Debug)]
    15→pub enum MatrixError {
    16→    /// Data dimension mismatch
    17→    #[error("Data dimension error: {0}")]
    18→    Dimension(String),
    19→    /// Variable not found in data
    20→    #[error("Variable not found: {0}")]
    21→    VariableNotFound(String),
    22→}
    23→
    24→/// High-performance design matrix builder with optimized memory layout
    25→pub struct Builder {
    26→    n_rows: usize,
    27→    columns: Vec<Vec<f64>>,
    28→}
    29→
    30→impl Builder {
    31→    /// Create a new builder for the given number of observations
    32→    pub fn new(n_rows: usize) -> Self {
    33→        Self {
    34→            n_rows,
    35→            columns: Vec::new(),
    36→        }
    37→    }
    38→
    39→    /// Add an intercept column (all ones)
    40→    pub fn add_intercept(&mut self) {
    41→        self.columns.push(vec![1.0; self.n_rows]);
    42→    }
    43→
    44→    /// Add a continuous variable column
    45→    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
    46→        if values.len() != self.n_rows {
    47→            return Err(MatrixError::Dimension(format!(
    48→                "Expected {} rows, got {}",
    49→                self.n_rows,
    50→                values.len()
    51→            )));
    52→        }
    53→        self.columns.push(values);
    54→        Ok(())
    55→    }
    56→
    57→    /// Build the final design matrix with optimized memory layout
    58→    pub fn build(self) -> Array2<f64> {
    59→        if self.columns.is_empty() {
    60→            return Array2::zeros((self.n_rows, 0));
    61→        }
    62→
    63→        let n_cols = self.columns.len();
    64→
    65→        // Optimized approach: construct directly from flattened data
    66→        // This avoids the double-allocation and improves cache performance
    67→        let total_elements = self.n_rows * n_cols;
    68→        let mut flat_data = Vec::with_capacity(total_elements);
    69→
    70→        // Build row by row for better memory locality
    71→        for row_idx in 0..self.n_rows {
    72→            for col_idx in 0..n_cols {
    73→                flat_data.push(self.columns[col_idx][row_idx]);
    74→            }
    75→        }
    76→
    77→        // Create array from pre-built data
    78→        Array2::from_shape_vec((self.n_rows, n_cols), flat_data)
    79→            .expect("Dimensions should match constructed data")
    80→    }
    81→}
    82→
    83→/// Data container for building design matrices
    84→#[derive(Debug)]
    85→pub struct DataContainer {
    86→    variables: std::collections::HashMap<String, Vec<f64>>,
    87→    n_rows: usize,
    88→}
    89→
    90→impl DataContainer {
    91→    /// Create a new data container
    92→    pub fn new(n_rows: usize) -> Self {
    93→        Self {
    94→            variables: std::collections::HashMap::new(),
    95→            n_rows,
    96→        }
    97→    }
    98→
    99→    /// Add a continuous variable to the data
   100→    pub fn add_variable(&mut self, name: String, values: Vec<f64>) -> Result<(), MatrixError> {
   101→        if values.len() != self.n_rows {
   102→            return Err(MatrixError::Dimension(format!(
   103→                "Variable '{}' has {} values but expected {}",
   104→                name,
   105→                values.len(),
   106→                self.n_rows
   107→            )));
   108→        }
   109→        self.variables.insert(name, values);
   110→        Ok(())
   111→    }
   112→
   113→    /// Get a variable by name
   114→    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
   115→        self.variables.get(name)
   116→    }
   117→}
   118→
   119→/// Build design matrix from model specification and data
   120→pub fn build_design_matrix(
   121→    spec: &ModelSpec,
   122→    data: &DataContainer,
   123→) -> Result<Array2<f64>, MatrixError> {
   124→    use formula::Term;
   125→
   126→    let mut builder = Builder::new(data.n_rows);
   127→    let mut column_names = Vec::new();
   128→
   129→    // Process each term in the model specification
   130→    for term in &spec.terms {
   131→        match term {
   132→            Term::Intercept => {
   133→                builder.add_intercept();
   134→                column_names.push("(Intercept)".to_string());
   135→            }
   136→            Term::Variable(var_name) => {
   137→                let values = data
   138→                    .get_variable(var_name)
   139→                    .ok_or_else(|| MatrixError::VariableNotFound(var_name.clone()))?;
   140→                builder.add_continuous(values.clone())?;
   141→                column_names.push(var_name.clone());
   142→            }
   143→            Term::Interaction(vars) => {
   144→                // For interaction terms, multiply the variables together
   145→                if vars.len() < 2 {
   146→                    return Err(MatrixError::Dimension(
   147→                        "Interaction term must have at least 2 variables".to_string(),
   148→                    ));
   149→                }
   150→
   151→                // Get the first variable
   152→                let first_var = match &vars[0] {
   153→                    Term::Variable(name) => data
   154→                        .get_variable(name)
   155→                        .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?,
   156→                    _ => {
   157→                        return Err(MatrixError::Dimension(
   158→                            "Interaction terms must contain variable names".to_string(),
   159→                        ))
   160→                    }
   161→                };
   162→
   163→                // Start with the first variable's values
   164→                let mut interaction_values = first_var.clone();
   165→                let mut interaction_name = match &vars[0] {
   166→                    Term::Variable(name) => name.clone(),
   167→                    _ => unreachable!(),
   168→                };
   169→
   170→                // Multiply by each subsequent variable
   171→                for var in &vars[1..] {
   172→                    match var {
   173→                        Term::Variable(name) => {
   174→                            let var_values = data
   175→                                .get_variable(name)
   176→                                .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?;
   177→
   178→                            for (i, value) in interaction_values.iter_mut().enumerate() {
   179→                                *value *= var_values[i];
   180→                            }
   181→                            interaction_name.push(':');
   182→                            interaction_name.push_str(name);
   183→                        }
   184→                        _ => {
   185→                            return Err(MatrixError::Dimension(
   186→                                "Interaction terms must contain variable names".to_string(),
   187→                            ))
   188→                        }
   189→                    }
   190→                }
   191→
   192→                builder.add_continuous(interaction_values)?;
   193→                column_names.push(interaction_name);
   194→            }
   195→            Term::FullInteraction(_) => {
   196→                // FullInteraction should be expanded before reaching here
   197→                return Err(MatrixError::Dimension(
   198→                    "FullInteraction terms should be expanded before matrix construction"
   199→                        .to_string(),
   200→                ));
   201→            }
   202→            Term::Function { name: _, args: _ } => {
   203→                // TODO: Implement function calls in future sprint
   204→                return Err(MatrixError::Dimension(
   205→                    "Function calls not yet implemented".to_string(),
   206→                ));
   207→            }
   208→        }
   209→    }
   210→
   211→    Ok(builder.build())
   212→}
   213→
   214→/// Build design matrix from model specification and data (legacy compatibility)
   215→pub fn build_design_matrix_legacy(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
   216→    // For backward compatibility with existing tests
   217→    let mut builder = Builder::new(2);
   218→    builder.add_intercept();
   219→    Ok(builder.build())
   220→}
   221→
   222→#[cfg(test)]
   223→mod tests {
   224→    use super::*;
   225→    use formula::parse_formula;
   226→
   227→    #[test]
   228→    fn test_data_container() {
   229→        let mut data = DataContainer::new(3);
   230→        let x_values = vec![1.0, 2.0, 3.0];
   231→
   232→        data.add_variable("x".to_string(), x_values.clone())
   233→            .unwrap();
   234→        assert_eq!(data.get_variable("x"), Some(&x_values));
   235→        assert_eq!(data.get_variable("nonexistent"), None);
   236→    }
   237→
   238→    #[test]
   239→    fn test_design_matrix_intercept_only() {
   240→        let spec = formula::ModelSpec::intercept_only("y");
   241→        let data = DataContainer::new(3);
   242→
   243→        let matrix = build_design_matrix(&spec, &data).unwrap();
   244→        assert_eq!(matrix.shape(), &[3, 1]);
   245→
   246→        // Check intercept column (all ones)
   247→        for i in 0..3 {
   248→            assert_eq!(matrix[[i, 0]], 1.0);
   249→        }
   250→    }
