     1→//! R-style formula parsing and design matrix specification
     2→//!
     3→//! This crate provides compile-time and run-time parsing of statistical formulas
     4→//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
     5→//! design matrix generators.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use pest::iterators::Pair;
    11→use pest::Parser;
    12→
    13→// Allow missing docs for generated code
    14→#[allow(missing_docs)]
    15→mod parser_generated {
    16→    use pest_derive::Parser;
    17→
    18→    /// Internal parser implementation for formula grammar
    19→    #[derive(Parser)]
    20→    #[grammar = "formula.pest"]
    21→    pub struct FormulaParser;
    22→}
    23→
    24→use parser_generated::{FormulaParser, Rule};
    25→
    26→/// Formula parsing errors
    27→#[derive(thiserror::Error, Debug)]
    28→pub enum FormulaError {
    29→    /// Parse error from pest
    30→    #[error("Formula parse error: {0}")]
    31→    Parse(String),
    32→    /// Semantic validation error
    33→    #[error("Formula validation error: {0}")]
    34→    Validation(String),
    35→}
    36→
    37→/// Abstract syntax tree representing a parsed statistical formula
    38→#[derive(Debug, Clone, PartialEq)]
    39→pub struct ModelSpec {
    40→    /// The response variable(s)
    41→    pub response: Vec<String>,
    42→    /// The predictor terms
    43→    pub terms: Vec<Term>,
    44→}
    45→
    46→/// A term in a statistical formula
    47→#[derive(Debug, Clone, PartialEq)]
    48→pub enum Term {
    49→    /// Intercept term
    50→    Intercept,
    51→    /// Variable name
    52→    Variable(String),
    53→    /// Interaction between terms (a:b)
    54→    Interaction(Vec<Term>),
    55→    /// Full interaction expansion (a*b = a + b + a:b)
    56→    FullInteraction(Vec<Term>),
    57→    /// Function call (e.g., I(x^2), poly(x, 2))
    58→    Function {
    59→        /// Function name
    60→        name: String,
    61→        /// Function arguments
    62→        args: Vec<String>,
    63→    },
    64→}
    65→
    66→impl ModelSpec {
    67→    /// Create a simple formula with intercept
    68→    pub fn intercept_only(response: &str) -> Self {
    69→        Self {
    70→            response: vec![response.to_string()],
    71→            terms: vec![Term::Intercept],
    72→        }
    73→    }
    74→
    75→    /// Add a variable term
    76→    pub fn add_variable(&mut self, var: &str) {
    77→        self.terms.push(Term::Variable(var.to_string()));
    78→    }
    79→
    80→    /// Expand all FullInteraction terms into their constituent parts
    81→    pub fn expand_interactions(&mut self) {
    82→        let mut expanded_terms = Vec::new();
    83→
    84→        for term in &self.terms {
    85→            match term {
    86→                Term::FullInteraction(vars) => {
    87→                    // Add main effects (each variable)
    88→                    for var in vars {
    89→                        if !expanded_terms.contains(var) {
    90→                            expanded_terms.push(var.clone());
    91→                        }
    92→                    }
    93→                    // Add interaction term
    94→                    expanded_terms.push(Term::Interaction(vars.clone()));
    95→                }
    96→                _ => {
    97→                    expanded_terms.push(term.clone());
    98→                }
    99→            }
   100→        }
   101→
   102→        self.terms = expanded_terms;
   103→    }
   104→}
   105→
   106→/// Parse a formula string into a ModelSpec  
   107→pub fn parse_formula(formula: &str) -> Result<ModelSpec, FormulaError> {
   108→    let mut pairs = FormulaParser::parse(Rule::formula, formula)
   109→        .map_err(|e| FormulaError::Parse(e.to_string()))?;
   110→
   111→    let formula_pair = pairs.next().unwrap();
   112→    let mut response = Vec::new();
   113→    let mut terms = Vec::new();
   114→
   115→    for pair in formula_pair.into_inner() {
   116→        match pair.as_rule() {
   117→            Rule::response => {
   118→                let var_pair = pair.into_inner().next().unwrap();
   119→                response.push(var_pair.as_str().trim().to_string());
   120→            }
   121→            Rule::terms => {
   122→                for term_pair in pair.into_inner() {
   123→                    if let Ok(term) = parse_term(term_pair) {
   124→                        terms.push(term);
   125→                    }
   126→                }
   127→            }
   128→            Rule::EOI => {}
   129→            _ => {}
   130→        }
   131→    }
   132→
   133→    let mut model_spec = ModelSpec { response, terms };
   134→    model_spec.expand_interactions();
   135→    Ok(model_spec)
   136→}
   137→
   138→fn parse_term(pair: Pair<Rule>) -> Result<Term, FormulaError> {
   139→    match pair.as_rule() {
   140→        Rule::term => {
   141→            let inner = pair.into_inner().next().unwrap();
   142→            parse_term(inner)
   143→        }
   144→        Rule::variable => Ok(Term::Variable(pair.as_str().trim().to_string())),
   145→        Rule::full_interaction => {
   146→            let mut variables = Vec::new();
   147→            for var_pair in pair.into_inner() {
   148→                if var_pair.as_rule() == Rule::variable {
   149→                    variables.push(Term::Variable(var_pair.as_str().trim().to_string()));
   150→                }
   151→            }
   152→            Ok(Term::FullInteraction(variables))
   153→        }
   154→        Rule::simple_interaction => {
   155→            let mut variables = Vec::new();
   156→            for var_pair in pair.into_inner() {
   157→                if var_pair.as_rule() == Rule::variable {
   158→                    variables.push(Term::Variable(var_pair.as_str().trim().to_string()));
   159→                }
   160→            }
   161→            Ok(Term::Interaction(variables))
   162→        }
   163→        _ => {
   164→            if pair.as_str() == "1" {
   165→                Ok(Term::Intercept)
   166→            } else {
   167→                Err(FormulaError::Parse(format!(
   168→                    "Unknown term: {}",
   169→                    pair.as_str()
   170→                )))
   171→            }
   172→        }
   173→    }
   174→}
   175→
   176→#[cfg(test)]
   177→mod tests {
   178→    use super::*;
   179→
   180→    #[test]
   181→    fn test_parse_simple_formula() {
   182→        let result = parse_formula("y ~ x").unwrap();
   183→        assert_eq!(result.response, vec!["y"]);
   184→        assert_eq!(result.terms.len(), 1);
   185→        assert_eq!(result.terms[0], Term::Variable("x".to_string()));
   186→    }
   187→
   188→    #[test]
   189→    fn test_parse_multiple_variables() {
   190→        let result = parse_formula("mpg ~ wt + hp").unwrap();
   191→        assert_eq!(result.response, vec!["mpg"]);
