//! R-style formula parsing and design matrix specification
//!
//! This crate provides compile-time and run-time parsing of statistical formulas
//! in the R format (e.g., `y ~ x1 + x2*x3`), compiling them into optimized
//! design matrix generators.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use pest::iterators::Pair;
use pest::Parser;

// Allow missing docs for generated code
#[allow(missing_docs)]
mod parser_generated {
    use pest_derive::Parser;

    /// Internal parser implementation for formula grammar
    #[derive(Parser)]
    #[grammar = "formula.pest"]
    pub struct FormulaParser;
}

use parser_generated::{FormulaParser, Rule};

/// Formula parsing errors
#[derive(thiserror::Error, Debug)]
pub enum FormulaError {
    /// Parse error from pest
    #[error("Formula parse error: {0}")]
    Parse(String),
    /// Semantic validation error
    #[error("Formula validation error: {0}")]
    Validation(String),
}

/// Abstract syntax tree representing a parsed statistical formula
#[derive(Debug, Clone, PartialEq)]
pub struct ModelSpec {
    /// The response variable(s)
    pub response: Vec<String>,
    /// The predictor terms
    pub terms: Vec<Term>,
}

/// A term in a statistical formula
#[derive(Debug, Clone, PartialEq)]
pub enum Term {
    /// Intercept term
    Intercept,
    /// Variable name
    Variable(String),
    /// Interaction between terms (a:b)
    Interaction(Vec<Term>),
    /// Full interaction expansion (a*b = a + b + a:b)
    FullInteraction(Vec<Term>),
    /// Function call (e.g., I(x^2), poly(x, 2))
    Function {
        /// Function name
        name: String,
        /// Function arguments
        args: Vec<String>,
    },
}

impl ModelSpec {
    /// Create a simple formula with intercept
    pub fn intercept_only(response: &str) -> Self {
        Self {
            response: vec![response.to_string()],
            terms: vec![Term::Intercept],
        }
    }

    /// Add a variable term
    pub fn add_variable(&mut self, var: &str) {
        self.terms.push(Term::Variable(var.to_string()));
    }

    /// Expand all FullInteraction terms into their constituent parts
    pub fn expand_interactions(&mut self) {
        let mut expanded_terms = Vec::new();

        for term in &self.terms {
            match term {
                Term::FullInteraction(vars) => {
                    // Add main effects (each variable)
                    for var in vars {
                        if !expanded_terms.contains(var) {
                            expanded_terms.push(var.clone());
                        }
                    }
                    // Add interaction term
                    expanded_terms.push(Term::Interaction(vars.clone()));
                }
                _ => {
                    expanded_terms.push(term.clone());
                }
            }
        }

        self.terms = expanded_terms;
    }
}

/// Parse a formula string into a ModelSpec  
pub fn parse_formula(formula: &str) -> Result<ModelSpec, FormulaError> {
    let mut pairs = FormulaParser::parse(Rule::formula, formula)
        .map_err(|e| FormulaError::Parse(e.to_string()))?;

    let formula_pair = pairs.next().unwrap();
    let mut response = Vec::new();
    let mut terms = Vec::new();

    for pair in formula_pair.into_inner() {
        match pair.as_rule() {
            Rule::response => {
                let var_pair = pair.into_inner().next().unwrap();
                response.push(var_pair.as_str().trim().to_string());
            }
            Rule::terms => {
                for term_pair in pair.into_inner() {
                    if let Ok(term) = parse_term(term_pair) {
                        terms.push(term);
                    }
                }
            }
            Rule::EOI => {}
            _ => {}
        }
    }

    let mut model_spec = ModelSpec { response, terms };
    model_spec.expand_interactions();
    Ok(model_spec)
}

fn parse_term(pair: Pair<Rule>) -> Result<Term, FormulaError> {
    match pair.as_rule() {
        Rule::term => {
            let inner = pair.into_inner().next().unwrap();
            parse_term(inner)
        }
        Rule::variable => Ok(Term::Variable(pair.as_str().trim().to_string())),
        Rule::full_interaction => {
            let mut variables = Vec::new();
            for var_pair in pair.into_inner() {
                if var_pair.as_rule() == Rule::variable {
                    variables.push(Term::Variable(var_pair.as_str().trim().to_string()));
                }
            }
            Ok(Term::FullInteraction(variables))
        }
        Rule::simple_interaction => {
            let mut variables = Vec::new();
            for var_pair in pair.into_inner() {
                if var_pair.as_rule() == Rule::variable {
                    variables.push(Term::Variable(var_pair.as_str().trim().to_string()));
                }
            }
            Ok(Term::Interaction(variables))
        }
        _ => {
            if pair.as_str() == "1" {
                Ok(Term::Intercept)
            } else {
                Err(FormulaError::Parse(format!(
                    "Unknown term: {}",
                    pair.as_str()
                )))
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_simple_formula() {
        let result = parse_formula("y ~ x").unwrap();
        assert_eq!(result.response, vec!["y"]);
        assert_eq!(result.terms.len(), 1);
        assert_eq!(result.terms[0], Term::Variable("x".to_string()));
    }

    #[test]
    fn test_parse_multiple_variables() {
        let result = parse_formula("mpg ~ wt + hp").unwrap();
        assert_eq!(result.response, vec!["mpg"]);
        assert_eq!(result.terms.len(), 2);
        assert_eq!(result.terms[0], Term::Variable("wt".to_string()));
        assert_eq!(result.terms[1], Term::Variable("hp".to_string()));
    }

    #[test]
    fn test_parse_full_interaction() {
        let result = parse_formula("y ~ x1 * x2").unwrap();
        assert_eq!(result.response, vec!["y"]);
        assert_eq!(result.terms.len(), 3); // x1 + x2 + x1:x2

        // Should have main effects
        assert_eq!(result.terms[0], Term::Variable("x1".to_string()));
        assert_eq!(result.terms[1], Term::Variable("x2".to_string()));

        // Should have interaction term
        if let Term::Interaction(vars) = &result.terms[2] {
            assert_eq!(vars.len(), 2);
            assert_eq!(vars[0], Term::Variable("x1".to_string()));
            assert_eq!(vars[1], Term::Variable("x2".to_string()));
        } else {
            panic!("Expected interaction term");
        }
    }

    #[test]
    fn test_parse_simple_interaction() {
        let result = parse_formula("y ~ x1 : x2").unwrap();
        assert_eq!(result.response, vec!["y"]);
        assert_eq!(result.terms.len(), 1); // Only x1:x2

        if let Term::Interaction(vars) = &result.terms[0] {
            assert_eq!(vars.len(), 2);
            assert_eq!(vars[0], Term::Variable("x1".to_string()));
            assert_eq!(vars[1], Term::Variable("x2".to_string()));
        } else {
            panic!("Expected interaction term");
        }
    }

    #[test]
    fn test_parse_complex_formula() {
        let result = parse_formula("mpg ~ wt + hp * cyl").unwrap();
        assert_eq!(result.response, vec!["mpg"]);
        assert_eq!(result.terms.len(), 4); // wt + hp + cyl + hp:cyl

        assert_eq!(result.terms[0], Term::Variable("wt".to_string()));
        assert_eq!(result.terms[1], Term::Variable("hp".to_string()));
        assert_eq!(result.terms[2], Term::Variable("cyl".to_string()));

        if let Term::Interaction(vars) = &result.terms[3] {
            assert_eq!(vars.len(), 2);
            assert_eq!(vars[0], Term::Variable("hp".to_string()));
            assert_eq!(vars[1], Term::Variable("cyl".to_string()));
        } else {
            panic!("Expected interaction term");
        }
    }

    #[test]
    fn test_invalid_formula() {
        let result = parse_formula("invalid formula without ~");
        assert!(result.is_err());
    }
}

//! High-level statistical modeling API for Rust
//!
//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
//! and `Glm` (Generalized Linear Models), integrating lower-level crates
//! to provide a complete modeling workflow.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::{prelude::*, Mat};
use family::Family;
use link::LinkFn;
use ndarray::{Array1, ArrayView1, ArrayView2};
use optimcore::{coordinate_descent, irls, CoordinateDescentConfig, IrlsConfig};
use resample::{bootstrap, BootstrapConfig, BootstrapResult, BootstrapStatistic};

/// Statistical modeling errors
#[derive(thiserror::Error, Debug)]
pub enum ModelError {
    /// Linear algebra computation error
    #[error("Linear algebra error: {0}")]
    LinearAlgebra(String),
    /// Invalid model specification
    #[error("Invalid model: {0}")]
    InvalidModel(String),
}

// Re-export important types for convenience
pub use family::{Binomial, Gaussian, Poisson};
pub use link::{Identity, Log, Logit};

/// Common trait for all fitted models
pub trait Fit {
    /// Get model coefficients
    fn coefficients(&self) -> &[f64];

    /// Get fitted values
    fn fitted(&self) -> &[f64];

    /// Get residuals
    fn residuals(&self) -> &[f64];

    /// Get model summary
    fn summary(&self) -> ModelSummary;

    /// Perform bootstrap resampling on the model
    fn bootstrap(&self, _n_samples: usize) -> Result<BootstrapResult, ModelError> {
        Err(ModelError::InvalidModel(
            "Bootstrap not implemented for this model type".to_string(),
        ))
    }
}

/// Model summary information
#[derive(Debug)]
pub struct ModelSummary {
    /// Coefficient table
    pub coefficients: Vec<CoefficientRow>,
    /// R-squared (coefficient of determination)
    pub r_squared: f64,
    /// Adjusted R-squared
    pub adj_r_squared: f64,
    /// Residual standard error
    pub residual_std_error: f64,
    /// F-statistic for overall model significance
    pub f_statistic: f64,
    /// p-value for F-statistic
    pub f_p_value: f64,
    /// Degrees of freedom for model (number of predictors excluding intercept)
    pub df_model: usize,
    /// Degrees of freedom for residuals
    pub df_residual: usize,
}

/// A row in the coefficient table
#[derive(Debug)]
pub struct CoefficientRow {
    /// Variable name
    pub name: String,
    /// Estimated coefficient
    pub estimate: f64,
    /// Standard error
    pub std_error: f64,
    /// t-statistic
    pub t_value: f64,
    /// p-value
    pub p_value: f64,
}

/// Linear model fitting
pub struct Lm;

/// Generalized linear model fitting
pub struct Glm;

/// Lasso regression (L1 regularization)
pub struct Lasso;

/// Ridge regression (L2 regularization)
pub struct Ridge;

/// Fitted linear model results
#[derive(Debug)]
pub struct LmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Matrix rank (for rank-deficient matrices)
    rank: usize,
    /// Design matrix for statistical inference (stored for covariance calculation)
    x_matrix: Mat<f64>,
}

/// Fitted generalized linear model results
#[derive(Debug)]
pub struct GlmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Linear predictor values (X * β)
    linear_predictor: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Design matrix for statistical inference
    x_matrix: Mat<f64>,
    /// Final deviance
    deviance: f64,
    /// Working weights from final IRLS iteration
    weights: Vec<f64>,
    /// Number of IRLS iterations
    iterations: usize,
    /// Whether IRLS converged
    converged: bool,
}

/// Fitted regularized model results (Lasso/Ridge)
#[derive(Debug)]
pub struct RegularizedFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Design matrix for bootstrap resampling
    x_matrix: Mat<f64>,
    /// Response vector for bootstrap resampling
    y_vector: Vec<f64>,
    /// Regularization parameter used
    lambda: f64,
    /// Elastic net mixing parameter (1.0 = Lasso, 0.0 = Ridge)
    alpha: f64,
    /// Number of coordinate descent iterations
    #[allow(dead_code)]
    iterations: usize,
    /// Whether algorithm converged
    #[allow(dead_code)]
    converged: bool,
}

impl Lm {
    /// Fit a linear model using ndarray views (recommended modern API)
    ///
    /// This implementation uses faer's column-pivoted QR decomposition to handle
    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    ///
    /// # Example
    /// ```
    /// use ndarray::Array2;
    /// use stats_models::Lm;
    ///
    /// // Create design matrix with intercept
    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
    /// let y = vec![3.0, 5.0, 7.0];
    ///
    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
    /// ```
    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
        let (n_rows, n_cols) = x.dim();

        if y.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        // Convert to faer matrices
        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);

        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
    }

    /// Fit a linear model using raw slices (legacy API for backward compatibility)
    ///
    /// This implementation uses faer's column-pivoted QR decomposition to handle
    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    ///
    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
    pub fn fit(
        x_data: &[f64],
        y_data: &[f64],
        n_rows: usize,
        n_cols: usize,
    ) -> Result<LmFit, ModelError> {
        if x_data.len() != n_rows * n_cols {
            return Err(ModelError::InvalidModel(
                "Design matrix dimensions don't match data".to_string(),
            ));
        }

        if y_data.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        // Create faer matrices from input data
        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);

        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
    }

    /// Internal fitting logic shared by both APIs
    fn fit_internal(
        x_mat: Mat<f64>,
        y_mat: Mat<f64>,
        n_rows: usize,
        n_cols: usize,
    ) -> Result<LmFit, ModelError> {
        // Use column-pivoted QR for numerical stability with rank-deficient matrices
        let qr = x_mat.col_piv_qr();

        // Calculate rank from R matrix diagonal elements
        let r_matrix = qr.R();
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }

        // Handle rank-deficient matrices by checking for numerical instability
        let coefficients_mat = qr.solve_lstsq(&y_mat);

        // Check for numerical instability and apply correction if needed
        let has_instability =
            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);

        let final_coefficients_mat = if has_instability {
            // For rank-deficient case, set coefficients for columns beyond rank to zero
            let mut corrected_coefs = Vec::new();
            for i in 0..coefficients_mat.nrows() {
                let coef = coefficients_mat[(i, 0)];
                if coef.abs() > 1e10 {
                    corrected_coefs.push(0.0);
                } else {
                    corrected_coefs.push(coef);
                }
            }
            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
        } else {
            coefficients_mat
        };

        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
        let fitted_mat = &x_mat * &final_coefficients_mat;

        // Calculate residuals: e = y - ŷ
        let residuals_mat = &y_mat - &fitted_mat;

        // Extract results to plain Vec<f64> for API
        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
            .map(|i| final_coefficients_mat[(i, 0)])
            .collect();

        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
            .map(|i| fitted_mat[(i, 0)])
            .collect();

        let residuals: Vec<f64> = (0..residuals_mat.nrows())
            .map(|i| residuals_mat[(i, 0)])
            .collect();

        // rank is already computed above using qr.rank()

        Ok(LmFit {
            coefficients,
            fitted_values,
            residuals,
            n_obs: n_rows,
            rank,
            x_matrix: x_mat,
        })
    }
}

impl LmFit {
    /// Get the number of observations used in the model
    pub fn n_obs(&self) -> usize {
        self.n_obs
    }

    /// Get the rank of the design matrix (number of linearly independent columns)
    pub fn rank(&self) -> usize {
        self.rank
    }

    /// Get degrees of freedom for error (n_obs - rank)
    pub fn df_resid(&self) -> usize {
        self.n_obs.saturating_sub(self.rank)
    }
}

impl Glm {
    /// Fit a generalized linear model using ndarray views
    ///
    /// This implementation uses the IRLS algorithm to fit GLMs with any
    /// exponential family distribution and link function.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `family` - Exponential family (Gaussian, Poisson, Binomial)
    /// * `start` - Optional starting values for coefficients
    /// * `config` - Optional IRLS configuration
    pub fn fit_ndarray<F>(
        x: ArrayView2<f64>,
        y: ArrayView1<f64>,
        family: F,
        start: Option<Array1<f64>>,
        config: Option<IrlsConfig>,
    ) -> Result<GlmFit, ModelError>
    where
        F: Family,
    {
        let (n_rows, n_cols) = x.dim();

        if y.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        let link = family.link();

        // Define closures for IRLS algorithm
        let link_fn = |mu: f64| link.link(mu);
        let inverse_link_fn = |eta: f64| link.inverse_link(eta);
        let mu_eta_fn = |eta: f64| link.mu_eta(eta);
        let variance_fn = |mu: f64| family.variance(mu);
        let dev_resid_fn = |y: f64, mu: f64| family.dev_resid(y, mu);

        let functions = optimcore::GlmFunctions {
            link_fn,
            inverse_link_fn,
            mu_eta_fn,
            variance_fn,
            dev_resid_fn,
        };

        // Run IRLS algorithm
        let irls_result = irls(x, y, functions, start, config)
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        // Calculate fitted values: μ = g⁻¹(X * β)
        let fitted_values: Vec<f64> = irls_result
            .linear_predictor
            .iter()
            .map(|&eta| inverse_link_fn(eta))
            .collect();

        // Calculate residuals: e = y - μ
        let residuals: Vec<f64> = y
            .iter()
            .zip(fitted_values.iter())
            .map(|(&y_val, &fitted)| y_val - fitted)
            .collect();

        // Convert ndarray to faer matrix for storage
        let x_matrix = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);

        Ok(GlmFit {
            coefficients: irls_result.params.to_vec(),
            fitted_values,
            residuals,
            linear_predictor: irls_result.linear_predictor.to_vec(),
            n_obs: n_rows,
            x_matrix,
            deviance: irls_result.deviance,
            weights: irls_result.weights.to_vec(),
            iterations: irls_result.iterations,
            converged: irls_result.converged,
        })
    }
}

impl GlmFit {
    /// Get the number of observations used in the model
    pub fn n_obs(&self) -> usize {
        self.n_obs
    }

    /// Get the deviance
    pub fn deviance(&self) -> f64 {
        self.deviance
    }

    /// Get the number of IRLS iterations
    pub fn iterations(&self) -> usize {
        self.iterations
    }

    /// Check if IRLS converged
    pub fn converged(&self) -> bool {
        self.converged
    }

    /// Get the linear predictor values
    pub fn linear_predictor(&self) -> &[f64] {
        &self.linear_predictor
    }

    /// Get the working weights from final iteration
    pub fn weights(&self) -> &[f64] {
        &self.weights
    }
}

impl Lasso {
    /// Fit a Lasso regression model using coordinate descent
    ///
    /// This implementation uses coordinate descent optimization with L1 regularization
    /// to encourage sparse solutions.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `lambda` - L1 regularization parameter (higher values = more regularization)
    /// * `config` - Optional coordinate descent configuration
    pub fn fit(
        x: ArrayView2<f64>,
        y: ArrayView1<f64>,
        lambda: f64,
        config: Option<CoordinateDescentConfig>,
    ) -> Result<RegularizedFit, ModelError> {
        let mut config = config.unwrap_or_default();
        config.lambda = lambda;
        config.alpha = 1.0; // Pure Lasso (L1 only)

        let result = coordinate_descent(x, y, Some(config))
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        let fitted_values: Vec<f64> = result.linear_predictor.to_vec();
        let residuals: Vec<f64> = y
            .iter()
            .zip(fitted_values.iter())
            .map(|(&y_val, &fitted)| y_val - fitted)
            .collect();

        // Store matrices for bootstrap resampling
        let x_matrix = Mat::from_fn(x.nrows(), x.ncols(), |i, j| x[[i, j]]);
        let y_vector = y.to_vec();

        Ok(RegularizedFit {
            coefficients: result.params.to_vec(),
            fitted_values,
            residuals,
            n_obs: x.nrows(),
            x_matrix,
            y_vector,
            lambda,
            alpha: 1.0,
            iterations: result.iterations,
            converged: result.converged,
        })
    }
}

impl Ridge {
    /// Fit a Ridge regression model using coordinate descent
    ///
    /// This implementation uses coordinate descent optimization with L2 regularization
    /// to shrink coefficients toward zero without enforcing sparsity.
    ///
    /// # Arguments
    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
    /// * `y` - Response vector as ndarray view (n_observations)
    /// * `lambda` - L2 regularization parameter (higher values = more regularization)
